-- Seed exercise library with full metadata.
-- Safe to re-run: ON CONFLICT updates metadata on existing rows.

ON CONFLICT (name) DO UPDATE SET
  training_quality = EXCLUDED.training_quality,
  muscle_group     = EXCLUDED.muscle_group,
  movement_pattern = EXCLUDED.movement_pattern,
  intensity_tier   = EXCLUDED.intensity_tier,
  bilateral        = EXCLUDED.bilateral,
  equipment        = EXCLUDED.equipment,
  notes            = EXCLUDED.notes,
  source           = EXCLUDED.source;
